{
  "formal_minutes": {
    "회의정보": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"]
    },
    "확정결정": [
      {
        "항목": "공개 릴리스 목표 시각",
        "내용": "스모크 테스트 통과 시 금요일 15:00 KST에 공개 릴리스"
      },
      {
        "항목": "packageName 불일치 대응 원칙",
        "내용": "불일치 발생 시 먼저 패키지 설정을 점검하고, 계약(컨트랙트) 자체가 잘못된 경우에만 smoke-theme-pack.mjs 검토"
      }
    ],
    "기각된제안": [
      {
        "제안자": "Hara",
        "제안": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "결론": "기각"
      }
    ],
    "내부스트레치목표": [
      {
        "항목": "수요일 릴리스 제안",
        "상태": "내부 스트레치 목표(확정 일정 아님)"
      }
    ],
    "비결정_또는_미확정": [
      {
        "항목": "README 설치 절차 검토",
        "내용": "가능하면 목요일까지 검토 제안, 담당자 미지정"
      },
      {
        "항목": "Hara tarball 경로 점검 완료 시각",
        "내용": "Minjun의 스모크 결과 공유 이후 수행, 정확한 기한 미설정"
      }
    ],
    "리스크": [
      "tarball 경로 오류 시 릴리스 지연 가능",
      "README 설치 절차가 오래된 경우 릴리스 노트가 사용자에게 오해를 줄 수 있음"
    ],
    "오픈질문": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 명시해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "미정",
      "task": "README 설치 절차 검토(가능하면 목요일)",
      "due": "목요일(가능 시)",
      "status": "담당자 미지정",
      "source_certainty": "부분확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성 tarball 경로 점검",
      "due": "미정",
      "status": "대기(선행 결과 필요)",
      "source_certainty": "확정(기한 제외)"
    }
  ],
  "followup_note": {
    "다음확인사항": [
      "금요일 10:00 KST 스모크 테스트 결과 통과/실패 여부 확인",
      "금요일 12:00 KST 이전 action_items.md 트리아지 노트 작성 여부 확인",
      "스모크 결과 공유 직후 tarball 경로 점검 결과 확인",
      "README 설치 절차 검토 담당자 지정 및 실제 반영 여부 확인",
      "최종 릴리스 승인 권한자 확정",
      "릴리스 노트에 수요일 내부 스트레치 목표 언급 여부 결정"
    ],
    "비발명주의사항": [
      "고객명/외부 파트너를 추가로 만들지 말 것",
      "예산 정보가 있었다고 쓰지 말 것",
      "보안 사고가 있었다고 쓰지 말 것",
      "프로덕션 장애가 있었다고 쓰지 말 것",
      "법무 승인 요건이 있었다고 쓰지 말 것",
      "미지정 담당자/기한을 임의 확정하지 말 것"
    ]
  },
  "non_invention_rules": {
    "금지추가사실": [
      "customer",
      "budget",
      "security_incident",
      "production_outage",
