      "unassigned_owner",
      "unset_deadline"
    ],
    "작성원칙": [
      "확정/기각/스트레치/리스크/오픈질문을 구분해 기록",
      "원문 노트에 없는 사실은 추론으로 보강하지 않음",
      "시간 정보는 노트에 제시된 KST 기준만 사용"
    ]
  }
